const clientData = $('Process One Client').item.json;
const adsData = $input.item.json;
const results = adsData.results || [];
const nomeCliente = clientData.nome_cliente || 'Cliente';
const whatsappRaw = clientData.whatsapp || '';

let campaignLines = '';
if (results.length === 0) {
  campaignLines = '⚠️ Nenhuma campanha ativa no período.';
} else {
  for (const row of results) {
    const campaign = row.campaign || {};
    const metrics = row.metrics || {};
    const name = campaign.name || 'Campanha sem nome';
    const impressions = parseInt(metrics.impressions || 0).toLocaleString('pt-BR');
    const clicks = parseInt(metrics.clicks || 0).toLocaleString('pt-BR');
    const costMicros = parseFloat(metrics.costMicros || metrics.cost_micros || 0);
    const cost = (costMicros / 1000000).toFixed(2);
    const ctr = (parseFloat(metrics.ctr || 0) * 100).toFixed(2);
    const avgCpcMicros = parseFloat(metrics.averageCpc || metrics.average_cpc || 0);
    const avgCpc = (avgCpcMicros / 1000000).toFixed(2);
    const conversions = parseFloat(metrics.conversions || 0).toFixed(0);
    campaignLines += `\n🔍 *${name}*\n`;
    campaignLines += `• Impressões: ${impressions}\n`;
    campaignLines += `• Cliques: ${clicks}\n`;
    campaignLines += `• CTR: ${ctr}%\n`;
    campaignLines += `• CPC Médio: R$${avgCpc}\n`;
    campaignLines += `• Investimento: R$${cost}\n`;
    campaignLines += `• Conversões: ${conversions}\n`;
  }
}

let phone = whatsappRaw.replace(/\D/g, '');
if (phone.length === 11 || phone.length === 10) phone = '55' + phone;

const message = `📊 *Relatório Semanal - ${nomeCliente}*\n📅 Período: últimos 7 dias\n\n🎯 *Campanhas Google Ads:*\n${campaignLines}\n💡 Dúvidas? Entre em contato!`;
return { json: { phone, message, nome_cliente: nomeCliente } };
